import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * 🧩 Dr. Fragment — PhD in Mdoularity & Structural Cohesion (TS/Bun)
 * Generated by Sovereign Forge.
 */
export class FragmentPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "fragment";
        this.name = "Fragment";
        this.emoji = "🧩";
        this.role = "PhD Refactoring Expert";
        this.phd_identity = "Mdoularity & Structural Cohesion (TS/Bun)";
        this.stack = "Bun";
        this.healingPrompt = "Fix the following component isolation or micro-frontend issue. Remove cross-boundary imports and enforce strict module isolation. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js"],
            rules: [
          {
                    "regex": "import\\s+.*\\s+from\\s+['\"]\\.\\.\\/\\.\\.\\/\\.\\.\\/",
                    "issue": "Coupling: Importação profunda detectada. Considere usar alias de caminhos ou refatorar para pacotes mais próximos.",
                    "severity": "low"
          },
          {
                    "regex": "class\\s+\\w+\\s+\\{.*constructor\\(.*\\)\\s+\\{.*new\\s+\\w+.*\\}.*\\}",
                    "issue": "Dependency Injection: Instanciação direta no construtor. Use injeção de dependência para facilitar testabilidade PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "export\\s+default",
                    "issue": "Clarity: Prefira named exports para facilitar o rastreio de dependências e refatorações automatizadas.",
                    "severity": "low"
          },
          {
                    "regex": "any",
                    "issue": "Type Quality: Uso de 'any' detectado. Violação grave da integridade de tipos; prefira 'unknown' ou tipos específicos.",
                    "severity": "high"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Fragment operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Fragment, PhD em Mdoularity & Structural Cohesion (TS/Bun). Sua missão é garantir a excelência via governança PhD.`;
    }
}
